package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"time"

	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// Public event-type strings emitted by agentlib.FizeauService.Execute, mirrored
// from CONTRACT-003 §"Event JSON shapes". Kept as constants here so the
// drain loop does not have to import the agent's internal/harnesses
// package (which is module-private).
const (
	serviceEventRoutingDecision = "routing_decision"
	serviceEventFinal           = "final"
)

// ServiceEvent payload types are now aliases to the upstream v0.8.0 public
// types (agent-f0bc5467). DDx previously maintained byte-for-byte shadow
// copies of these structs because CONTRACT-003 hadn't published them; that
// left the consumer carrying stream-adjacent knowledge and drifted whenever
// upstream shapes changed. With v0.8.0 the types are public and stable.
//
// Aliases rather than an outright delete so existing call sites keep
// working without a sweep. New code can (and should) use agentlib types
// directly.
type (
	serviceFinalData = agentlib.ServiceFinalData
)

type serviceRoutingActual struct {
	Harness                     string
	Provider                    string
	Model                       string
	PredictedPower              int
	PredictedSpeedTPS           float64
	PredictedCostUSDPer1kTokens float64
	PredictedCostSource         string
}

// useNewAgentPath reports whether RunAgent should dispatch to the new
// agentlib.FizeauService.Execute path. Default is on. Set the env var
// DDX_USE_NEW_AGENT_PATH=0 (or "false") to disable as an emergency escape
// hatch.
func useNewAgentPath() bool {
	switch os.Getenv("DDX_USE_NEW_AGENT_PATH") {
	case "0", "false", "FALSE", "False":
		return false
	default:
		return true
	}
}

// runAgentViaService is the new RunAgent dispatch path that drives the
// agent through agentlib.FizeauService.Execute and drains the resulting event
// channel into a DDx Result. Old in-package code paths (RunAgent legacy
// loop, embeddedCompactionConfig, buildAgentProvider, findTool, and
// wrapProviderWithDeadlines) stay in place; this function does NOT call them.
//
// Stall detection: we delegate to the agent's StallPolicy. The agent
// emits a stall event then a final event with Status="stalled".
func runAgentViaService(r *Runner, opts RunArgs) (*Result, error) {
	promptText, err := r.resolvePrompt(opts)
	if err != nil {
		return nil, err
	}

	model := r.resolveModel(opts, "agent")
	timeout := r.resolveTimeout(opts)
	wallClock := r.resolveWallClock(opts)

	wd := opts.WorkDir
	if wd == "" {
		wd, _ = os.Getwd()
	}

	// Construct the service. Reuses NewServiceFromWorkDir so provider/model
	// routing data lands on the agent the same way every other DDx command
	// constructs it (see serviceconfig.go).
	svc, err := NewServiceFromWorkDir(wd)
	if err != nil {
		return nil, fmt.Errorf("agent: build service: %w", err)
	}

	// Resolve where to write the per-request session log.
	logDir := opts.SessionLogDir
	if logDir == "" {
		logDir = r.Config.SessionLogDir
	}
	if logDir == "" {
		logDir = DefaultLogDir
	}

	providerTimeout := ResolveProviderRequestTimeout(wd, opts.Provider, model, 0)

	// Build the public ExecuteRequest per CONTRACT-003.
	req := agentlib.ServiceExecuteRequest{
		Prompt:          promptText,
		Model:           model,
		Provider:        opts.Provider,
		Harness:         "agent",
		ModelRef:        opts.ModelRef,
		Reasoning:       agentlib.Reasoning(opts.Effort),
		Permissions:     opts.Permissions,
		WorkDir:         wd,
		Timeout:         wallClock,
		IdleTimeout:     timeout,
		ProviderTimeout: providerTimeout,
		SessionLogDir:   logDir,
		Metadata:        opts.Correlation,
		Role:            opts.Role,
		CorrelationID:   opts.CorrelationID,
	}

	parentCtx := opts.Context
	if parentCtx == nil {
		parentCtx = context.Background()
	}
	ctx, cancel := context.WithCancel(parentCtx)
	defer cancel()

	start := time.Now()
	events, err := svc.Execute(ctx, req)
	if err != nil {
		return nil, fmt.Errorf("agent: execute: %w", err)
	}

	final, routing, actualPower, _ := drainServiceEvents(events)
	elapsed := time.Since(start)

	result := &Result{
		Harness:    "agent",
		Model:      model,
		DurationMS: int(elapsed.Milliseconds()),
	}
	if routing != nil {
		result.Provider = routing.Provider
		if routing.Model != "" {
			result.Model = routing.Model
		}
		result.PredictedPower = routing.PredictedPower
		result.PredictedSpeedTPS = routing.PredictedSpeedTPS
		result.PredictedCostUSDPer1kTokens = routing.PredictedCostUSDPer1kTokens
		result.PredictedCostSource = routing.PredictedCostSource
	}
	if actualPower > 0 {
		result.ActualPower = actualPower
	}
	if final != nil {
		// Normalized final text from the upstream harness (agent-32e8ff5e).
		result.Output = final.FinalText
		if final.Usage != nil {
			// v0.9.1: Usage fields became *int so the API can distinguish
			// "harness reported zero" from "harness didn't report". Treat
			// nil as zero for DDx's int-valued result struct.
			if final.Usage.InputTokens != nil {
				result.InputTokens = *final.Usage.InputTokens
			}
			if final.Usage.OutputTokens != nil {
				result.OutputTokens = *final.Usage.OutputTokens
			}
			if final.Usage.TotalTokens != nil {
				result.Tokens = *final.Usage.TotalTokens
			}
		}
		if final.CostUSD > 0 {
			result.CostUSD = final.CostUSD
		}
		result.ExitCode = final.ExitCode
		result.Error = final.Error
		if final.RoutingActual != nil {
			if result.Provider == "" {
				result.Provider = final.RoutingActual.Provider
			}
			if final.RoutingActual.Model != "" {
				result.Model = final.RoutingActual.Model
			}
		}
		if final.SessionLogPath != "" {
			// surface as session ID for downstream cross-reference (mirrors
			// the legacy path's AgentSessionID population).
			result.AgentSessionID = final.SessionLogPath
		}
	}
	result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)

	promptSource := opts.PromptSource
	if promptSource == "" {
		if opts.PromptFile != "" {
			promptSource = opts.PromptFile
		} else {
			promptSource = "inline"
		}
	}
	r.logSession(result, len(promptText), promptText, promptSource, opts.Correlation)
	r.recordRoutingOutcome(result, elapsed, opts)
	return result, nil
}

// drainServiceEvents reads service events and returns the final-event payload,
// the routing decision (when present in the routing_decision start event), the
// power of the selected model (0 when the routing_decision event does not
// include candidate power components), and any canonical progress payloads
// emitted by the service.
func drainServiceEvents(events <-chan agentlib.ServiceEvent) (*serviceFinalData, *serviceRoutingActual, int, []agentlib.ServiceProgressData) {
	var final *serviceFinalData
	var routing *serviceRoutingActual
	var routingPower int
	var progress []agentlib.ServiceProgressData

	for ev := range events {
		switch string(ev.Type) {
		case serviceEventRoutingDecision:
			var payload struct {
				Harness    string `json:"harness"`
				Provider   string `json:"provider"`
				Model      string `json:"model"`
				Candidates []struct {
					Model              string  `json:"model"`
					Eligible           bool    `json:"eligible"`
					CostUSDPer1kTokens float64 `json:"cost_usd_per_1k_tokens"`
					CostSource         string  `json:"cost_source"`
					Components         struct {
						Power    int     `json:"power"`
						SpeedTPS float64 `json:"speed_tps"`
					} `json:"components"`
				} `json:"candidates"`
			}
			if err := json.Unmarshal(ev.Data, &payload); err == nil {
				routing = &serviceRoutingActual{
					Harness:  payload.Harness,
					Provider: payload.Provider,
					Model:    payload.Model,
				}
				for _, c := range payload.Candidates {
					if c.Eligible && c.Model == payload.Model {
						routingPower = c.Components.Power
						routing.PredictedPower = c.Components.Power
						routing.PredictedSpeedTPS = c.Components.SpeedTPS
						routing.PredictedCostUSDPer1kTokens = c.CostUSDPer1kTokens
						routing.PredictedCostSource = c.CostSource
						break
					}
				}
			}
		case agentlib.ServiceEventTypeProgress:
			var data agentlib.ServiceProgressData
			if err := json.Unmarshal(ev.Data, &data); err == nil {
				progress = append(progress, data)
			}
		case serviceEventFinal:
			var data serviceFinalData
			if err := json.Unmarshal(ev.Data, &data); err == nil {
				final = &data
			}
		}

		}
	}
	return final, routing, routingPower, progress
}

package agent

// service_run.go provides Runner-free helpers that drive every operation via
// the agentlib.FizeauService service surface (CONTRACT-003). RunWithConfigViaService
// is the only run entry point; legacy RunViaService/RunViaServiceWith and the
// runFixtureHarnessViaRunner shim were retired in B22d-h.

import (
	"context"
	"fmt"
	"os"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// serviceRunFactory, when non-nil, overrides NewServiceFromWorkDir inside
// RunWithConfigViaService. CLI-level integration tests inject a stub to
// observe ServiceExecuteRequest fields without a real agent server.
var serviceRunFactory func(workDir string) (agentlib.FizeauService, error)

// SetServiceRunFactory installs a service factory for RunWithConfigViaService.
// Pass nil to restore production behavior. Exported for cmd/ integration tests.
//
// Production reachability: invoked from init() with nil so the symbol is
// reachable from main() under deadcode RTA. Real overrides come from cmd/
// integration tests at test-setup time.
func SetServiceRunFactory(f func(workDir string) (agentlib.FizeauService, error)) {
	serviceRunFactory = f
}

func init() {
	// Reach SetServiceRunFactory from main() so it survives deadcode RTA.
	// The nil reset is a no-op: production never sets the factory.
	SetServiceRunFactory(nil)
}

// appendProviderTimeoutHint appends a configuration override hint to errMsg
// when it indicates a provider request timeout fired. Helps operators find
// the knob to adjust (AC4 of ddx-2c63bb95).
func appendProviderTimeoutHint(errMsg string, providerTimeout time.Duration) string {
	if errMsg == "" || !strings.Contains(errMsg, "provider request timeout") {
		return errMsg
	}
	return errMsg + fmt.Sprintf(
		"; request_timeout=%s exceeded — override via"+
			" agent.endpoints.<name>.request_timeout_seconds in .ddx/config.yaml"+
			" or pass --request-timeout DURATION to execute-bead/execute-loop",
		providerTimeout.Round(time.Second),
	)
}

// RunWithConfigViaService dispatches a single agent invocation through the
// agent service. It takes a sealed ResolvedConfig (durable knobs) and an
// AgentRunRuntime (per-invocation plumbing/intent), and is the SD-024
// successor to the retired RunViaService/RunViaServiceWith entry points.
//
// The virtual and script harnesses route through a DDx-owned Runner path,
// not the upstream service. These are not "carve-outs pending migration" —
// they are different products from upstream's same-named stubs. DDx's
// virtual is a content-addressed record/replay dictionary keyed by
// PromptHash; upstream's is a unit-test stub where callers stuff
// virtual.response into Metadata. DDx's script reads a filesystem directive
// file; upstream does not model this at all.
func RunWithConfigViaService(ctx context.Context, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
	if ctx == nil {
		ctx = context.Background()
	}

	harness := rcfg.Passthrough().Harness

	if harness == "virtual" || harness == "script" {
		sessionLogDir := runtime.SessionLogDirOverride
		if sessionLogDir == "" {
			sessionLogDir = rcfg.SessionLogDir()
		}
		cfg := Config{SessionLogDir: ResolveLogDir(workDir, "")}
		r := NewRunner(cfg)
		r.WorkDir = workDir
		return r.runInternal(RunArgs{
			Context:       ctx,
			Harness:       rcfg.Harness(),
			Prompt:        runtime.Prompt,
			PromptFile:    runtime.PromptFile,
			PromptSource:  runtime.PromptSource,
			Correlation:   runtime.Correlation,
			Model:         rcfg.Model(),
			Provider:      rcfg.Provider(),
			ModelRef:      rcfg.ModelRef(),
			Effort:        rcfg.Effort(),
			Timeout:       rcfg.Timeout(),
			WallClock:     rcfg.WallClock(),
			WorkDir:       runtime.WorkDir,
			Permissions:   rcfg.Permissions(),
			SessionLogDir: sessionLogDir,
		})
	}

	factory := serviceRunFactory
	if factory == nil {
		factory = NewServiceFromWorkDir
	}
	svc, err := factory(workDir)
	if err != nil {
		return nil, fmt.Errorf("agent: build service: %w", err)
	}
	return executeOnService(ctx, svc, workDir, rcfg, runtime)
}

// executeOnService dispatches against a pre-built svc using the durable
// knobs from rcfg and per-invocation plumbing from runtime, then records
// one session-index row. It is the inlined replacement for the retired
// RunViaServiceWith helper and is shared with dispatchViaResolvedConfig.
func executeOnService(ctx context.Context, svc agentlib.FizeauService, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
	if svc == nil {
		return nil, fmt.Errorf("agent: nil service")
	}
	if ctx == nil {
		ctx = context.Background()
	}

	promptText := runtime.Prompt
	if runtime.PromptFile != "" {
		data, err := readPromptFileBounded(runtime.PromptFile)
		if err != nil {
			return nil, fmt.Errorf("agent: read prompt file: %w", err)
		}
		promptText = string(data)
	}
	if promptText == "" {
		return nil, fmt.Errorf("agent: prompt is required")
	}

	wd := runtime.WorkDir
	if wd == "" {
		wd = workDir
	}
	if wd == "" {
		wd, _ = os.Getwd()
	}

	idle := rcfg.Timeout()
	if idle <= 0 {
		idle = time.Duration(DefaultTimeoutMS) * time.Millisecond
	}
	wall := rcfg.WallClock()
	if wall <= 0 {
		wall = time.Duration(DefaultWallClockMS) * time.Millisecond
	}

	sessionLogDir := runtime.SessionLogDirOverride
	if sessionLogDir == "" {
		sessionLogDir = rcfg.SessionLogDir()
	}
	if sessionLogDir == "" {
		sessionLogDir = ResolveLogDir(workDir, "")
	}

	pt := rcfg.Passthrough()

	harness := runtime.HarnessOverride
	if harness == "" {
		harness = pt.Harness
	}

	model := runtime.ModelOverride
	if model == "" {
		model = pt.Model
	}

	permissions := runtime.PermissionsOverride
	if permissions == "" {
		permissions = rcfg.Permissions()
	}

	providerTimeout := ResolveProviderRequestTimeout(workDir, pt.Provider, model, rcfg.ProviderRequestTimeout())

	minPower := rcfg.MinPower()
	if runtime.MinPowerOverride > 0 {
		minPower = runtime.MinPowerOverride
	}

	req := agentlib.ServiceExecuteRequest{
		Prompt:          promptText,
		Model:           model,
		Profile:         rcfg.Profile(),
		Provider:        pt.Provider,
		Harness:         harness,
		ModelRef:        rcfg.ModelRef(),
		Reasoning:       agentlib.Reasoning(rcfg.Effort()),
		Permissions:     permissions,
		WorkDir:         wd,
		Timeout:         wall,
		IdleTimeout:     idle,
		ProviderTimeout: providerTimeout,
		SessionLogDir:   sessionLogDir,
		Metadata:        runtime.Correlation,
		Role:            runtime.Role,
		CorrelationID:   runtime.CorrelationID,
		MinPower:        minPower,
		MaxPower:        rcfg.MaxPower(),
	}

	cancelCtx, cancel := context.WithCancel(ctx)
	defer cancel()

	start := time.Now().UTC()
	events, err := svc.Execute(cancelCtx, req)
	if err != nil {
		return nil, fmt.Errorf("agent: execute: %w", err)
	}

	final, routing, actualPower, _ := drainServiceEvents(events)
	finishedAt := time.Now().UTC()
	elapsed := finishedAt.Sub(start)

	result := &Result{
		Harness:    harness,
		Model:      model,
		DurationMS: int(elapsed.Milliseconds()),
	}
	if routing != nil {
		result.Provider = routing.Provider
		if routing.Model != "" {
			result.Model = routing.Model
		}
		if routing.Harness != "" {
			result.Harness = routing.Harness
		}
		result.PredictedPower = routing.PredictedPower
		result.PredictedSpeedTPS = routing.PredictedSpeedTPS
		result.PredictedCostUSDPer1kTokens = routing.PredictedCostUSDPer1kTokens
		result.PredictedCostSource = routing.PredictedCostSource
	}
	if actualPower > 0 {
		result.ActualPower = actualPower
	}
	if final != nil {
		// Normalized final text from the upstream harness (agent-32e8ff5e);
		// reviewer verdict extraction now parses this instead of raw stream
		// frames (ddx-7bc0c8d5).
		result.Output = final.FinalText
		if final.Usage != nil {
			// v0.9.1: Usage fields became *int (nullable).
			if final.Usage.InputTokens != nil {
				result.InputTokens = *final.Usage.InputTokens
			}
			if final.Usage.OutputTokens != nil {
				result.OutputTokens = *final.Usage.OutputTokens
			}
			if final.Usage.TotalTokens != nil {
				result.Tokens = *final.Usage.TotalTokens
			}
		}
		if final.CostUSD > 0 {
			result.CostUSD = final.CostUSD
		}
		result.ExitCode = final.ExitCode
		result.Error = final.Error
		if final.RoutingActual != nil {
			if result.Provider == "" {
				result.Provider = final.RoutingActual.Provider
			}
			if final.RoutingActual.Model != "" {
				result.Model = final.RoutingActual.Model
			}
		}
		if final.SessionLogPath != "" {
			result.AgentSessionID = final.SessionLogPath
		}
	}
	result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
	entry := SessionIndexEntryFromResult(workDir, SessionIndexInputs{
		Harness:     harness,
		Model:       model,
		Provider:    pt.Provider,
		Effort:      rcfg.Effort(),
		Correlation: runtime.Correlation,
	}, result, start, finishedAt)
	_ = AppendSessionIndex(ResolveLogDir(workDir, ""), entry, finishedAt)
	return result, nil
}

